import os

def list_files_in_directory(directory):
    """
    Belirtilen dizindeki tüm dosyaları listeler.

    Args:
        directory (str): Dosyaların listeleneceği dizinin yolu.

    Returns:
        list: Dizin içindeki dosyaların listesi.
    """
    try:
        files = [f for f in os.listdir(directory) if os.path.isfile(os.path.join(directory, f))]
        return files
    except FileNotFoundError:
        return "Dizin bulunamadı."

if __name__ == '__main__':
    directory_path = "."  # Şu anki dizin. Farklı bir dizin için yolu değiştirebilirsiniz.
    file_list = list_files_in_directory(directory_path)

    if isinstance(file_list, str):
        print(file_list)  # Hata mesajını yazdır
    else:
        if file_list:
            print("Dizin içindeki dosyalar:")
            for file in file_list:
                print(file)
        else:
            print("Dizin içinde dosya bulunamadı.")
